1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	  material?: string;
6	}
7	
8	interface Damage {
9	  type: string;
10	  amount: number;
11	}
12	
13	interface Step {
14	  type: string;
15	  items?: Item[];
16	  policy?: number;
17	  damages?: Damage[];
18	}
19	
20	interface Customer {
21	  yearsWithMHPCO: number;
22	  quoteNumber?: number;
23	}
24	
25	interface Scenario {
26	  customer: Customer;
27	  steps: Step[];
28	}
29	
30	const PROCESSING_FEE = 5;
31	const FIRST_INSURANCE_RATE = 0.1;
32	
33	const BASE_PREMIUM: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
41	
42	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
43	const BLOCK_SIZE = 3;
44	const BLOCK_PREMIUM = 60;
45	const CURSE_SURCHARGE_RATE = 0.5;
46	const HIGH_ENCHANTMENT_THRESHOLD = 5;
47	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
48	const LOYALTY_THRESHOLD_YEARS = 2;
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
51	const DEDUCTIBLE = 100;
52	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
53	const FULL_REIMBURSEMENT_RATE = 1;
54	const CLAIM_HALF_REIMBURSEMENT_RATE = 0.5;
55	const INSURANCE_CAP_MULTIPLIER = 2;
56	
57	const INSURANCE_VALUE: Record<string, number> = {
58	  sword: 1000,
59	  rune: 250,
60	  amulet: 600,
61	};
62	
63	function calculateBasePremium(items: Item[]): number {
64	  const typeCounts: Record<string, number> = {};
65	  for (const item of items) {
66	    typeCounts[item.type] = (typeCounts[item.type] || 0) + 1;
67	  }
68	
69	  return Object.entries(typeCounts).reduce((total, [type, count]) => {
70	    const premium = COMPONENT_TYPES.has(type) && count === BLOCK_SIZE
71	      ? BLOCK_PREMIUM
72	      : count * BASE_PREMIUM[type];
73	    return total + premium;
74	  }, 0);
75	}
76	
77	function calculateLoyaltyDiscount(customer: Customer, basePremium: number): number {
78	  return customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
79	    ? basePremium * LOYALTY_DISCOUNT_RATE
80	    : 0;
81	}
82	
83	function calculateFollowUpDiscount(customer: Customer, basePremium: number): number {
84	  return (customer.quoteNumber ?? 1) >= 2
85	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
86	    : 0;
87	}
88	
89	function calculateItemSurcharges(items: Item[]): number {
90	  return items.reduce((total, item) => {
91	    const itemBasePremium = BASE_PREMIUM[item.type];
92	    const curseSurcharge = item.cursed ? itemBasePremium * CURSE_SURCHARGE_RATE : 0;
93	    const enchantmentSurcharge = (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
94	      ? itemBasePremium * HIGH_ENCHANTMENT_SURCHARGE_RATE
95	      : 0;
96	    return total + curseSurcharge + enchantmentSurcharge;
97	  }, 0);
98	}
99	
100	function calculateInsuranceCap(policyItems: Item[]): number {
101	  const insuranceSum = policyItems.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
102	  return insuranceSum * INSURANCE_CAP_MULTIPLIER;
103	}
104	
105	function calculateClaimPayout(damages: Damage[], policyItems: Item[]): number {
106	  return damages.reduce((sum, damage) => {
107	    const matchingItem = policyItems.find(item => item.type === damage.type);
108	    const hasHighEnchantment = matchingItem !== undefined && (matchingItem.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
109	    const reimbursementRate = hasHighEnchantment ? CLAIM_HALF_REIMBURSEMENT_RATE : FULL_REIMBURSEMENT_RATE;
110	    return sum + Math.max(damage.amount * reimbursementRate - DEDUCTIBLE, 0);
111	  }, 0);
112	}
113	
114	export function processScenario(scenario: Scenario): unknown[] {
115	  const results: unknown[] = [];
116	
117	  for (const step of scenario.steps) {
118	    if (step.type === "quote") {
119	      const items = step.items!;
120	      const basePremium = calculateBasePremium(items);
121	      const itemSurcharges = calculateItemSurcharges(items);
122	      const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
123	      const loyaltyDiscount = calculateLoyaltyDiscount(scenario.customer, basePremium);
124	      const followUpDiscount = calculateFollowUpDiscount(scenario.customer, basePremium);
125	      const premium = Math.ceil(basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
126	      results.push({ premium });
127	    } else if (step.type === "claim") {
128	      const policyItems = scenario.steps[step.policy!].items!;
129	      const cap = calculateInsuranceCap(policyItems);
130	      const totalPayout = calculateClaimPayout(step.damages!, policyItems);
131	      const payout = Math.min(totalPayout, cap);
132	      const remainingCap = cap - payout;
133	      results.push({ payout, remainingCap });
134	    }
135	  }
136	
137	  return results;
138	}
